import Image from "next/image";
import { getLocale, getTranslations } from "next-intl/server";

import { ProductCard } from "@/components/common/product-card";
import { PageContainer } from "@/components/layout/page-container";
import { BannerImageSlider } from "@/components/marketing/banner-image-slider";
import { Link } from "@/i18n/routing";
import type { Locale } from "@/i18n/routing";
import { getStorefrontHomeCategorySections } from "@/lib/products";
import { getStorefrontBanners } from "@/lib/storefront";
import type { PaperbaseBanner } from "@/types/paperbase";

export default async function HomePage() {
  const [tHome, categorySections, homeTopBanners, homeBottomBanners, locale] = await Promise.all([
    getTranslations("home"),
    getStorefrontHomeCategorySections(),
    getStorefrontBanners("home_top"),
    getStorefrontBanners("home_bottom"),
    getLocale(),
  ]);
  const bannerHasAnyImage = (banner: PaperbaseBanner) =>
    Boolean(banner.image_url) || banner.images.some((item) => Boolean(item.image_url));
  const toBannerSlides = (banner: PaperbaseBanner) => {
    const fromApiImages = banner.images.filter((item) => Boolean(item.image_url));
    if (fromApiImages.length > 0) {
      return fromApiImages;
    }
    return banner.image_url
      ? [{ public_id: banner.public_id, image_url: banner.image_url, order: 0 }]
      : [];
  };

  const heroBanner = homeTopBanners.find((banner) => bannerHasAnyImage(banner)) ?? null;
  const hasBottomBanners = homeBottomBanners.length > 0;
  const heroSlides = heroBanner ? toBannerSlides(heroBanner) : [];

  function FullBleedBannerBlock({ banners }: { banners: PaperbaseBanner[] }) {
    if (banners.length === 0) {
      return null;
    }

    return (
      <div className="w-full space-y-6 md:space-y-8">
        {banners.map((banner) => (
          <section key={banner.public_id} className="w-full">
            {bannerHasAnyImage(banner) ? (
              <div className="relative w-full">
                <BannerImageSlider
                  title={banner.title}
                  headlineFallback={tHome("headline")}
                  images={toBannerSlides(banner)}
                  height={1200}
                  viewportClassName="h-[230px] sm:h-[320px] md:h-screen"
                  showTitleOverlay={Boolean(banner.title?.trim())}
                />
              </div>
            ) : (
              <PageContainer>
                <div className="card mx-auto max-w-4xl px-4 py-6 text-center md:px-6">
                  <p className="text-pretty text-base font-semibold leading-snug text-foreground md:text-lg">{banner.title}</p>
                </div>
              </PageContainer>
            )}
          </section>
        ))}
      </div>
    );
  }

  return (
    <div
      className={`bg-card ${heroBanner?.image_url ? "pt-0" : "pt-4 md:pt-6"} ${hasBottomBanners ? "pb-0" : "pb-10 md:pb-14"}`}
    >
      {heroBanner ? (
        <section className="mb-10 w-full md:mb-12">
          {heroSlides.length > 0 ? (
            <BannerImageSlider
              title={heroBanner.title}
              headlineFallback={tHome("headline")}
              images={heroSlides}
              priority
              height={1200}
              viewportClassName="h-[230px] sm:h-[320px] md:h-screen"
            />
          ) : (
            <Image
              src={heroBanner.image_url!}
              alt={heroBanner.title?.trim() ? heroBanner.title : tHome("headline")}
              width={2400}
              height={1200}
              priority
              sizes="100vw"
              className="block h-auto w-full max-w-full"
              style={{ width: "100%", height: "auto" }}
            />
          )}
        </section>
      ) : null}

      <PageContainer>
        <section id="products" className="space-y-12 md:space-y-16">
          {categorySections.length === 0 ? (
            <p className="card mx-auto max-w-lg text-center text-sm text-foreground/80">{tHome("emptyProducts")}</p>
          ) : (
            <>
              {categorySections.map((section, sectionIdx) => (
                <div key={section.slug} className="space-y-5 md:space-y-6">
                  <header className="mx-auto max-w-4xl px-1 text-center">
                    <h2 className="text-pretty text-2xl font-light tracking-tight text-foreground md:text-3xl lg:text-4xl">
                      {section.name}
                    </h2>
                    {section.description ? (
                      <p className="mx-auto mt-3 max-w-3xl text-pretty text-base font-normal leading-snug text-foreground/85 md:mt-4 md:text-lg md:leading-relaxed">
                        {section.description}
                      </p>
                    ) : null}
                  </header>
                  <div className="grid grid-cols-2 gap-4 sm:gap-6 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5">
                    {section.products.map((product, productIdx) => (
                      <ProductCard
                        key={product.public_id}
                        product={product}
                        locale={locale as Locale}
                        priority={sectionIdx === 0 && productIdx === 0}
                        aosDelay={(productIdx + 1) * 100}
                      />
                    ))}
                  </div>
                  {section.showViewMore ? (
                    <div className="flex justify-center pt-1">
                      <Link
                        href={`/categories/${section.slug}`}
                        className="inline-flex h-10 items-center justify-center rounded-lg border border-border bg-card px-5 text-sm font-medium text-foreground shadow-sm transition-colors hover:bg-muted"
                      >
                        {tHome("viewMore")}
                      </Link>
                    </div>
                  ) : null}

                </div>
              ))}
            </>
          )}
        </section>
      </PageContainer>

      <div className="mt-12 md:mt-16">
        <FullBleedBannerBlock banners={homeBottomBanners} />
      </div>
    </div>
  );
}

import type { ReactNode } from "react";

import "@/styles/globals.css";
import "aos/dist/aos.css";
import { Geist } from "next/font/google";
import { ThemeProvider } from "@/lib/theme/ThemeProvider";
import { THEME_CACHE_VERSION, THEME_LS_KEY, THEME_LS_VERSION_KEY } from "@/lib/theme/themeCacheKeys";
import { cn } from "@/lib/utils";

const geist = Geist({ subsets: ["latin"], variable: "--font-sans", preload: false });


type RootLayoutProps = {
  children: ReactNode;
};

export default function RootLayout({ children }: RootLayoutProps) {
  return (
    <html lang="und" suppressHydrationWarning className={cn("font-sans", geist.variable)}>
      <head>
        <script
          dangerouslySetInnerHTML={{
            __html: `
        try {
          const v = localStorage.getItem('${THEME_LS_VERSION_KEY}');
          const t = localStorage.getItem('${THEME_LS_KEY}');
          if (v === '${THEME_CACHE_VERSION}' && t) {
            const p = JSON.parse(t).resolved_palette;
            const r = document.documentElement;
            Object.entries(p).forEach(([k, val]) => {
              r.style.setProperty('--' + k, val);
            });
            var headerBg = p['header'] || p['background'];
            if (headerBg && typeof headerBg === 'string') {
              var hex = headerBg.trim();
              if (hex.charAt(0) === '#') hex = hex.slice(1);
              if (hex.length === 3 && /^[0-9a-fA-F]{3}$/.test(hex)) {
                hex = hex.charAt(0)+hex.charAt(0)+hex.charAt(1)+hex.charAt(1)+hex.charAt(2)+hex.charAt(2);
              }
              if (hex.length === 6 && /^[0-9a-fA-F]{6}$/.test(hex)) {
                var r0 = parseInt(hex.slice(0,2), 16);
                var g0 = parseInt(hex.slice(2,4), 16);
                var b0 = parseInt(hex.slice(4,6), 16);
                var lum = (0.299*r0 + 0.587*g0 + 0.114*b0)/255;
                r.setAttribute('data-theme-mode', lum < 0.5 ? 'dark' : 'light');
              }
            }
          }
        } catch(e) {}
      `,
          }}
        />
        <link rel="preconnect" href="https://fonts.googleapis.com" />
        <link rel="preconnect" href="https://fonts.gstatic.com" crossOrigin="" />
        <link
          href="https://fonts.googleapis.com/css2?family=Archivo:ital,wght@0,100..900;1,100..900&family=Noto+Sans+Bengali:wght@100..900&display=swap"
          rel="stylesheet"
        />
      </head>
      <body className="min-h-screen bg-background text-foreground antialiased">
        <ThemeProvider>{children}</ThemeProvider>
      </body>
    </html>
  );
}

"use client";

import { useTranslations } from "next-intl";
import { startTransition, useEffect, useState } from "react";

import { VariantSelectionProvider, useVariantSelection } from "@/components/product/product-variant-selection";
import { useCart } from "@/hooks/useCart";
import { getProductDetailCached, peekProductDetailCache } from "@/lib/client/product-detail-cache";
import { parseVariantAttributePairs } from "@/lib/variant-details";
import { cn } from "@/lib/utils";
import type { CartItem } from "@/types/cart";
import type { ProductDetail } from "@/types/product";

function VariantSync({
  detail,
  item,
}: {
  detail: ProductDetail;
  item: CartItem;
}) {
  const tCheckout = useTranslations("checkout");
  const tVariant = useTranslations("variantModal");
  const productT = useTranslations("product");
  const { selectedValues, setSelectedValue, selectedVariant, optionsByAttribute } = useVariantSelection();
  const { updateItemVariant } = useCart();

  const allGroupsSelected = Object.keys(selectedValues).length === optionsByAttribute.size;

  useEffect(() => {
    if (!selectedVariant) return;
    if (selectedVariant.public_id === item.variant_public_id) return;
    startTransition(() => {
      updateItemVariant(item.product_public_id, item.variant_public_id, {
        product_public_id: item.product_public_id,
        product_slug: detail.slug,
        variant_public_id: selectedVariant.public_id,
        name: detail.name,
        price: selectedVariant.price,
        image_url: detail.image_url,
        max_quantity: detail.stock_tracking ? selectedVariant.available_quantity : undefined,
        variant_details: selectedVariant.options.map((o) => `${o.attribute_name}: ${o.value}`).join(", "),
      });
    });
  }, [detail, item.product_public_id, item.variant_public_id, selectedVariant, updateItemVariant]);

  return (
    <div className="mt-3 space-y-3">
      {[...optionsByAttribute.entries()].map(([slug, data]) => (
        <div key={slug}>
          <p className="mb-2 text-xs font-bold uppercase tracking-normal text-primary">
            {data.attribute_name}
            {selectedValues[slug] ? (
              <span className="ml-1.5 font-semibold normal-case tracking-normal text-foreground">
                : {data.values.find((v) => v.value_public_id === selectedValues[slug])?.value}
              </span>
            ) : null}
          </p>
          <div className="flex flex-wrap gap-2">
            {data.values.map((value) => {
              const selected = selectedValues[slug] === value.value_public_id;
              return (
                <button
                  key={value.value_public_id}
                  type="button"
                  onClick={() => setSelectedValue(slug, value.value_public_id)}
                  aria-pressed={selected}
                  className={cn(
                    "inline-flex min-h-9 cursor-pointer items-center rounded-md px-3.5 py-2 text-xs font-semibold sm:text-sm",
                    selected
                      ? "bg-primary text-primary-foreground shadow-sm"
                      : "border border-border bg-card text-foreground hover:border-primary/30",
                  )}
                >
                  {value.value}
                </button>
              );
            })}
          </div>
        </div>
      ))}

      <div className="min-h-[1.25rem] pt-0.5">
        {!allGroupsSelected ? (
          <p className="text-xs font-medium text-primary/70">{tVariant("selectAllOptions")}</p>
        ) : selectedVariant == null ? (
          <p className="text-xs font-medium text-danger">{tVariant("unavailableCombination")}</p>
        ) : selectedVariant.stock_status === "out_of_stock" ? (
          <p className="text-xs font-medium text-muted-foreground">{productT("outOfStock")}</p>
        ) : detail.stock_tracking ? (
          <p className="text-xs font-medium text-primary/80">
            {tCheckout("stockAvailable", { count: selectedVariant.available_quantity })}
          </p>
        ) : (
          <p className="text-xs font-medium text-emerald-700">{tVariant("inStock")}</p>
        )}
      </div>
    </div>
  );
}

function StaticVariantBadges({ item }: { item: CartItem }) {
  const variantPairs = parseVariantAttributePairs(item.variant_details);
  if (variantPairs.length === 0) return null;
  return (
    <div className="mt-3 flex flex-wrap gap-3">
      {variantPairs.map((pair, idx) => (
        <div key={`${pair.label}-${pair.value}-${idx}`} className="min-w-0">
          {pair.label ? (
            <p className="text-xs font-bold uppercase tracking-normal text-muted-foreground">{pair.label}</p>
          ) : null}
          <span className="mt-1 inline-flex rounded bg-primary px-2.5 py-1 text-xs font-medium text-primary-foreground">
            {pair.value}
          </span>
        </div>
      ))}
    </div>
  );
}

export function CheckoutLineVariants({ item }: { item: CartItem }) {
  const slug = item.product_slug;
  const cachedInitial = slug ? peekProductDetailCache(slug) : null;

  const [detail, setDetail] = useState<ProductDetail | null>(() => cachedInitial);
  const [loadError, setLoadError] = useState(false);
  const [loading, setLoading] = useState(() => Boolean(slug) && !cachedInitial);

  useEffect(() => {
    if (!slug) {
      startTransition(() => {
        setDetail(null);
        setLoadError(false);
        setLoading(false);
      });
      return;
    }

    const cached = peekProductDetailCache(slug);
    if (cached) {
      startTransition(() => {
        setDetail(cached);
        setLoadError(false);
        setLoading(false);
      });
      return;
    }

    let cancelled = false;
    startTransition(() => {
      setLoading(true);
      setLoadError(false);
    });
    getProductDetailCached(slug)
      .then((data) => {
        if (!cancelled) setDetail(data);
      })
      .catch(() => {
        if (!cancelled) {
          setLoadError(true);
          setDetail(null);
        }
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });
    return () => {
      cancelled = true;
    };
  }, [slug]);

  if (!slug || loadError) {
    return <StaticVariantBadges item={item} />;
  }

  if (loading) {
    return (
      <div className="mt-3 space-y-3 animate-pulse" aria-busy="true">
        <div className="h-3 w-16 rounded bg-neutral-100" />
        <div className="flex gap-2">
          <div className="h-9 w-14 rounded-md bg-neutral-100" />
          <div className="h-9 w-14 rounded-md bg-neutral-100" />
        </div>
        <div className="h-3 w-40 rounded bg-neutral-100" />
      </div>
    );
  }

  const variants = detail?.variants ?? [];
  if (variants.length === 0 || !detail) {
    return <StaticVariantBadges item={item} />;
  }

  if (!item.variant_public_id) {
    return <StaticVariantBadges item={item} />;
  }

  return (
    <VariantSelectionProvider variants={variants} initialVariantPublicId={item.variant_public_id}>
      <VariantSync detail={detail} item={item} />
    </VariantSelectionProvider>
  );
}

"use client";

import Image from "next/image";
import { Check, Copy, Loader2, Phone, ShoppingCart } from "lucide-react";
import { useLocale, useTranslations } from "next-intl";
import { useEffect, useRef, useState } from "react";

import { formatPaperbaseError } from "@/lib/api/paperbase-errors";
import { submitMfsPayment } from "@/lib/client/checkout-mfs-api";
import { writeCheckoutSuccessMeta } from "@/lib/checkout/order-success-meta";
import { useRouter } from "@/i18n/routing";
import { parseDecimal } from "@/lib/format";
import { cn } from "@/lib/utils";
import { triggerPurchase } from "@/lib/tracker";
import type { PaperbaseOrderReceipt, PaperbaseStorePublic } from "@/types/paperbase";
import type { Locale } from "@/i18n/routing";

import { readStoredOrder, writeStoredOrder } from "@/components/orders/order-storage-keys";

import { CheckoutBreadcrumbs } from "./checkout-breadcrumbs";
import { clearMfsPendingOrderPublicId, readMfsPendingOrderPublicId, writeMfsPendingOrderPublicId } from "./checkout-storage-keys";

import { apiFetchJson } from "@/lib/client/api";

const BKASH_LOGO_SRC = "/assets/payment-provider/BKash-bKash2-Logo.wine.svg";
const NAGAD_LOGO_SRC = "/assets/payment-provider/Nagad-Logo.wine.svg";
const BKASH_PINK = "#D12053";
const BKASH_TERMS_URL = "https://www.bkash.com/en/page/terms-and-conditions";
/** Nagad wordmark red from `Nagad-Logo.wine.svg` */
const NAGAD_RED = "#ed1c24";
const NAGAD_TERMS_URL = "https://nagad.com.bd/en/terms/";

function isValidMfsMsisdn(value: string): boolean {
  const digits = value.replace(/\s/g, "");
  return /^01[3-9]\d{8}$/.test(digits);
}

type MfsProviderDetail = "bkash" | "nagad";

function formatTakaAmount(value: string, locale: Locale): string {
  return new Intl.NumberFormat(locale === "bn" ? "bn-BD" : "en-BD", {
    style: "currency",
    currency: "BDT",
    currencyDisplay: "narrowSymbol",
    maximumFractionDigits: 2,
  }).format(parseDecimal(value));
}

export function CheckoutMfsPayment() {
  const t = useTranslations("checkout");
  const tCommon = useTranslations("common");
  const locale = useLocale() as Locale;
  const router = useRouter();

  const [orderPublicId, setOrderPublicId] = useState<string | null>(null);
  const [receipt, setReceipt] = useState<PaperbaseOrderReceipt | null>(null);
  const [ready, setReady] = useState(false);
  const [payLoading, setPayLoading] = useState(false);
  const [errorText, setErrorText] = useState<string | null>(null);

  const [mfsView, setMfsView] = useState<"select" | MfsProviderDetail>("select");
  const [transactionId, setTransactionId] = useState("");
  const [payerPhone, setPayerPhone] = useState("");
  const [storePublic, setStorePublic] = useState<PaperbaseStorePublic | null>(null);
  const [storeInfoLoading, setStoreInfoLoading] = useState(true);
  const [storeNumberCopied, setStoreNumberCopied] = useState(false);
  const copyStoreNumberTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    let orderId = params.get("orderId")?.trim() || null;
    if (!orderId) {
      orderId = readMfsPendingOrderPublicId();
    }
    if (!orderId || !orderId.startsWith("ord_")) {
      router.replace("/checkout");
      return;
    }
    writeMfsPendingOrderPublicId(orderId);

    const r = readStoredOrder(orderId);
    if (!r) {
      clearMfsPendingOrderPublicId();
      router.replace("/checkout");
      return;
    }
    if (!r.requires_payment) {
      writeCheckoutSuccessMeta(orderId, { payment_method: "mfs" });
      clearMfsPendingOrderPublicId();
      router.replace(`/success/${orderId}`);
      return;
    }

    const ps = r.payment_status ?? "none";
    if (ps === "submitted" || ps === "verified") {
      writeCheckoutSuccessMeta(orderId, { payment_method: "mfs" });
      clearMfsPendingOrderPublicId();
      router.replace(`/success/${orderId}`);
      return;
    }

    setReceipt(r);
    setOrderPublicId(orderId);
    setReady(true);
  }, [router]);

  useEffect(() => {
    if (mfsView !== "bkash" && mfsView !== "nagad") {
      setStoreInfoLoading(true);
      return;
    }
    let cancelled = false;
    setStoreInfoLoading(true);
    setStorePublic(null);
    apiFetchJson<PaperbaseStorePublic>("/store/public")
      .then((s) => {
        if (!cancelled) setStorePublic(s);
      })
      .catch(() => {
        if (!cancelled) setStorePublic(null);
      })
      .finally(() => {
        if (!cancelled) setStoreInfoLoading(false);
      });
    return () => {
      cancelled = true;
    };
  }, [mfsView]);

  useEffect(() => {
    return () => {
      if (copyStoreNumberTimerRef.current) {
        clearTimeout(copyStoreNumberTimerRef.current);
      }
    };
  }, []);

  async function copyStoreNumberToClipboard() {
    const raw = storePublic?.phone?.replace(/\s/g, "") ?? "";
    if (!raw || storeInfoLoading) return;
    try {
      await navigator.clipboard.writeText(raw);
      setStoreNumberCopied(true);
      if (copyStoreNumberTimerRef.current) clearTimeout(copyStoreNumberTimerRef.current);
      copyStoreNumberTimerRef.current = setTimeout(() => {
        setStoreNumberCopied(false);
        copyStoreNumberTimerRef.current = null;
      }, 2000);
    } catch {
      /* clipboard unavailable */
    }
  }

  async function handleConfirmPayment(provider: MfsProviderDetail) {
    if (payLoading) return;
    if (!orderPublicId) {
      setErrorText(t("mfsMissingOrder"));
      return;
    }

    const tx = transactionId.trim();
    if (!tx) {
      setErrorText(
        provider === "bkash" ? t("bkashErrorTransactionRequired") : t("nagadErrorTransactionRequired"),
      );
      return;
    }
    if (tx.length > 100) {
      setErrorText(provider === "bkash" ? t("bkashErrorTransactionLength") : t("nagadErrorTransactionLength"));
      return;
    }
    const pn = payerPhone.trim();
    if (!isValidMfsMsisdn(pn)) {
      setErrorText(provider === "bkash" ? t("bkashErrorPhone") : t("nagadErrorPhone"));
      return;
    }

    setPayLoading(true);
    setErrorText(null);
    try {
      const next = await submitMfsPayment(orderPublicId, {
        transaction_id: tx,
        payer_number: pn.replace(/\s/g, ""),
      });
      clearMfsPendingOrderPublicId();
      writeStoredOrder(next);
      triggerPurchase({
        order_id: next.public_id,
        value: Number(next.total),
        items: next.items.map((line) => ({
          id: line.product_name,
          quantity: line.quantity,
          item_price: Number(line.unit_price),
        })),
        customer: {
          phone: pn.replace(/\s/g, ""),
        },
      });
      writeCheckoutSuccessMeta(orderPublicId, {
        payment_method: "mfs",
        mfs_provider: provider,
      });
      router.replace(`/success/${orderPublicId}`);
    } catch (error) {
      const msg = formatPaperbaseError(error);
      if (msg.includes("already been submitted")) {
        setErrorText(t("paymentAlreadySubmittedHint"));
      } else {
        setErrorText(msg);
      }
    } finally {
      setPayLoading(false);
    }
  }

  if (!ready || !receipt || !orderPublicId) {
    return (
      <div className="bg-card pb-12 pt-6 md:pb-16 md:pt-8">
        <CheckoutBreadcrumbs step="mfsProvider" />
        <div className="mx-auto max-w-xl rounded-lg border border-border bg-card p-8 shadow-sm md:p-10">
          <div className="h-8 max-w-xs animate-pulse rounded-md bg-neutral-100" />
          <div className="mt-4 h-4 max-w-md animate-pulse rounded-md bg-neutral-100" />
          <div className="mt-8 grid gap-8">
            <div className="space-y-2">
              <div className="h-4 w-32 animate-pulse rounded bg-neutral-100" />
              <div className="h-24 animate-pulse rounded-lg border border-neutral-200 bg-neutral-50" />
            </div>
            <div className="space-y-2">
              <div className="h-4 w-32 animate-pulse rounded bg-neutral-100" />
              <div className="h-24 animate-pulse rounded-lg border border-neutral-200 bg-neutral-50" />
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (mfsView === "bkash" || mfsView === "nagad") {
    const provider = mfsView;
    const brandColor = provider === "bkash" ? BKASH_PINK : NAGAD_RED;
    const logoSrc = provider === "bkash" ? BKASH_LOGO_SRC : NAGAD_LOGO_SRC;
    const termsUrl = provider === "bkash" ? BKASH_TERMS_URL : NAGAD_TERMS_URL;
    const helplineTel = provider === "bkash" ? "16247" : "16167";

    const gatewayHeading = provider === "bkash" ? t("bkashGatewayHeading") : t("nagadGatewayHeading");
    const storePhonePending = provider === "bkash" ? t("bkashStorePhonePending") : t("nagadStorePhonePending");
    const storePhoneMissing = provider === "bkash" ? t("bkashStorePhoneMissing") : t("nagadStorePhoneMissing");
    const invoiceLabel = provider === "bkash" ? t("bkashInvoiceLabel") : t("nagadInvoiceLabel");
