          )
        ) : null}
      </div>

      {/* Add to Cart button */}
      <button
        type="button"
        disabled={!canAdd}
        onClick={handleAdd}
        className={cn(
          "flex h-12 w-full cursor-pointer items-center justify-center gap-2 rounded-md px-4 text-sm font-bold tracking-wide text-primary-foreground transition-all",
          "bg-primary hover:bg-primary/90 active:scale-[0.98]",
          "disabled:cursor-not-allowed disabled:opacity-50",
        )}
      >
        <ShoppingCart className="size-4 shrink-0" strokeWidth={2} aria-hidden />
        {outOfStock ? productT("outOfStock") : t("addToCart")}
      </button>
    </div>
  );
});

// ─── Skeleton while loading ────────────────────────────────────────────────

function VariantPickerSkeleton() {
  return (
    <div className="animate-pulse space-y-5">
      <div className="flex items-center gap-3">
        <div className="h-16 w-16 shrink-0 rounded-lg bg-neutral-100" />
        <div className="flex-1 space-y-2">
          <div className="h-3.5 w-3/4 rounded bg-neutral-100" />
          <div className="h-3 w-1/3 rounded bg-neutral-100" />
        </div>
      </div>
      <div className="space-y-3">
        <div className="h-3 w-1/4 rounded bg-neutral-100" />
        <div className="flex gap-2">
          {[1, 2, 3].map((i) => (
            <div key={i} className="h-9 w-16 rounded-md bg-neutral-100" />
          ))}
        </div>
      </div>
      <div className="h-12 rounded-md bg-neutral-100" />
    </div>
  );
}

// ─── Public component ──────────────────────────────────────────────────────

export function ProductCardVariantModal({ product, variant = "default" }: Props) {
  const t = useTranslations("variantModal");
  const productT = useTranslations("product");
  const tCard = useTranslations("productCard");

  const [open, setOpen] = useState(false);
  const [detail, setDetail] = useState<ProductDetail | null>(null);
  const [loadError, setLoadError] = useState(false);

  const isCard = variant === "card";
  const isIcon = variant === "icon";
  const triggerLabel = isCard ? tCard("addToCart") : productT("addToCart");
  const disabled = product.stock_status === "out_of_stock";
  const prefetchDetail = useCallback(() => {
    if (Array.isArray(product.variants) && product.variants.length > 0) {
      return;
    }
    void getProductDetailCached(product.slug);
  }, [product]);

  const fetchDetail = useCallback(async () => {
    setLoadError(false);
    try {
      if (Array.isArray(product.variants) && product.variants.length > 0) {
        setDetail({
          public_id: product.public_id,
          name: product.name,
          slug: product.slug,
          image_url: product.image_url,
          price: product.price,
          original_price: product.original_price,
          stock_status: product.stock_status,
          available_quantity: product.available_quantity,
          brand: product.brand,
          category_public_id: product.category_public_id,
          category_slug: product.category_slug,
          category_name: product.category_name,
          extra_data: product.extra_data,
          prepayment_type: product.prepayment_type,
          stock_tracking: true,
          description: "",
          images: [],
          variants: product.variants,
          related_products: [],
        });
        return;
      }
      const seeded = peekProductDetailCache(product.slug);
      if (seeded) {
        setDetail(seeded);
        return;
      }
      const data = await getProductDetailCached(product.slug);
      setDetail(data);
    } catch {
      setLoadError(true);
    }
  }, [product]);

  useEffect(() => {
    if (open) {
      if (Array.isArray(product.variants) && product.variants.length > 0) {
        setDetail({
          public_id: product.public_id,
          name: product.name,
          slug: product.slug,
          image_url: product.image_url,
          price: product.price,
          original_price: product.original_price,
          stock_status: product.stock_status,
          available_quantity: product.available_quantity,
          brand: product.brand,
          category_public_id: product.category_public_id,
          category_slug: product.category_slug,
          category_name: product.category_name,
          extra_data: product.extra_data,
          prepayment_type: product.prepayment_type,
          stock_tracking: true,
          description: "",
          images: [],
          variants: product.variants,
          related_products: [],
        });
        return;
      }
      const seeded = peekProductDetailCache(product.slug);
      if (seeded) {
        setDetail(seeded);
        return;
      }
      fetchDetail();
    }
  }, [open, fetchDetail, product]);

  return (
    <DialogRoot open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <button
          type="button"
          disabled={disabled}
          onMouseEnter={prefetchDetail}
          onTouchStart={prefetchDetail}
          aria-label={disabled ? productT("outOfStock") : triggerLabel}
          className={cn(
            "flex cursor-pointer items-center justify-center transition-colors duration-200 ease-out",
            isIcon
              ? "size-9 rounded-full bg-background text-foreground shadow-sm ring-1 ring-foreground/10 hover:bg-background/95 hover:ring-foreground/15"
              : "w-full text-primary-foreground",
            isCard
              ? "gap-2 rounded-md py-2.5 text-sm font-medium bg-primary hover:bg-primary/90 active:bg-primary/95"
              : isIcon
                ? ""
                : "h-8 gap-1 rounded-md text-[11px] font-semibold sm:h-9 sm:gap-1.5 sm:text-[13px] bg-primary hover:bg-primary/90",
            "disabled:cursor-not-allowed disabled:bg-muted disabled:text-muted-foreground disabled:hover:bg-muted",
            isIcon && "disabled:bg-muted disabled:text-muted-foreground",
          )}
        >
          {isIcon ? (
            <Heart className="size-5 shrink-0" strokeWidth={1.75} aria-hidden />
          ) : (
            <ShoppingCart
              className={cn(
                "shrink-0 stroke-[2]",
                isCard ? "size-[18px]" : "size-3.5 sm:size-4 md:size-4",
              )}
              aria-hidden
            />
          )}
          {isIcon ? <span className="sr-only">{disabled ? productT("outOfStock") : triggerLabel}</span> : <span>{disabled ? productT("outOfStock") : triggerLabel}</span>}
        </button>
      </DialogTrigger>

      <DialogContent aria-describedby={undefined}>
        <DialogHeader>
          <DialogTitle>{t("title")}</DialogTitle>
        </DialogHeader>

        <div className="mt-4">
          {loadError ? (
            <div className="space-y-3 text-center py-4">
              <p className="text-sm text-muted-foreground">{t("loadError")}</p>
              <button
                type="button"
                onClick={fetchDetail}
                className="cursor-pointer text-sm font-semibold text-primary underline underline-offset-2"
              >
                {t("retry")}
              </button>
            </div>
          ) : detail == null ? (
            <VariantPickerSkeleton />
          ) : (
            <VariantSelectionProvider variants={detail.variants}>
              <VariantPicker detail={detail} onAdded={() => setOpen(false)} />
            </VariantSelectionProvider>
          )}
        </div>
      </DialogContent>
    </DialogRoot>
  );
}

"use client";

import { useEffect, useRef } from "react";

type DesktopNavbarScrollVisibilityProps = {
  targetId: string;
};

export function DesktopNavbarScrollVisibility({ targetId }: DesktopNavbarScrollVisibilityProps) {
  const lastYRef = useRef(0);
  const latestYRef = useRef(0);
  const isHiddenRef = useRef(false);
  const tickingRef = useRef(false);
  const rafIdRef = useRef<number | null>(null);
  const velocityRef = useRef(0);

  useEffect(() => {
    const el = document.getElementById(targetId);
    if (!el) return;

    const prefersReducedMotion =
      typeof window !== "undefined" &&
      window.matchMedia?.("(prefers-reduced-motion: reduce)")?.matches;

    const desktopMql = window.matchMedia?.("(min-width: 768px)");

    const VELOCITY_THRESHOLD = 4;
    const HIDE_THRESHOLD = 80;

    const setHidden = (hide: boolean) => {
      const header = document.getElementById(targetId);
      if (!header) return;

      if (!desktopMql?.matches) {
        // Ensure visible when not on desktop.
        header.style.transition = "";
        header.style.transform = "";
        isHiddenRef.current = false;
        return;
      }

      if (hide === isHiddenRef.current) return;
      isHiddenRef.current = hide;

      if (prefersReducedMotion) {
        header.style.transition = "none";
      } else if (hide) {
        header.style.transition = "transform 180ms cubic-bezier(0.4, 0, 1, 1)";
      } else {
        header.style.transition = "transform 280ms cubic-bezier(0.22, 1, 0.36, 1)";
        header.offsetHeight; // force reflow so transition reliably fires
      }

      header.style.transform = hide ? "translateY(-100%)" : "translateY(0)";
    };

    const processScroll = () => {
      tickingRef.current = false;

      if (!desktopMql?.matches) {
        setHidden(false);
        lastYRef.current = window.scrollY;
        latestYRef.current = window.scrollY;
        velocityRef.current = 0;
        return;
      }

      const currentY = latestYRef.current;
      const delta = currentY - lastYRef.current;
      velocityRef.current = velocityRef.current * 0.6 + delta * 0.4;

      if (currentY <= HIDE_THRESHOLD) {
        setHidden(false);
        lastYRef.current = currentY;
        velocityRef.current = 0;
        return;
      }

      if (velocityRef.current > VELOCITY_THRESHOLD && !isHiddenRef.current) {
        setHidden(true);
      } else if (velocityRef.current < -VELOCITY_THRESHOLD && isHiddenRef.current) {
        setHidden(false);
      }

      lastYRef.current = currentY;
    };

    const onScroll = () => {
      latestYRef.current = window.scrollY;
      if (!tickingRef.current) {
        tickingRef.current = true;
        rafIdRef.current = requestAnimationFrame(processScroll);
      }
    };

    // Initialize.
    el.style.willChange = "transform";
    el.style.transform = "translateY(0)";
    lastYRef.current = window.scrollY;
    latestYRef.current = window.scrollY;

    window.addEventListener("scroll", onScroll, { passive: true });

    const onMediaChange = () => {
      setHidden(false);
    };
    desktopMql?.addEventListener?.("change", onMediaChange);

    return () => {
      window.removeEventListener("scroll", onScroll);
      desktopMql?.removeEventListener?.("change", onMediaChange);
      if (rafIdRef.current != null) cancelAnimationFrame(rafIdRef.current);
    };
  }, [targetId]);

  return null;
}

