"use client";

import { useEffect, useMemo, useState } from "react";
import { X } from "lucide-react";
import { usePathname } from "@/i18n/routing";

import {
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogRoot,
  DialogTitle,
} from "@/components/ui/dialog";
import type { PaperbaseStorePopup } from "@/types/paperbase";

function formatLocalYmd(d: Date) {
  const year = d.getFullYear();
  const month = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

function truncateWords(text: string, maxWords: number): string {
  const words = text.trim().split(/\s+/).filter(Boolean);
  if (words.length <= maxWords) return text.trim();
  return `${words.slice(0, maxWords).join(" ")}...`;
}

export function GlobalPromoPopup({ popup }: { popup: PaperbaseStorePopup | null }) {
  const pathname = usePathname();
  const [open, setOpen] = useState(false);
  const images = useMemo(() => {
    const list = (popup?.images ?? []).slice().sort((a, b) => a.order - b.order).slice(0, 3);
    return list.filter((img) => Boolean(img.image_url));
  }, [popup]);

  const heroImage = images[0]?.image_url ?? null;
  const buttonText = popup?.button_text?.trim() ?? "";
  const buttonLink = popup?.button_link?.trim() ?? "";
  const descriptionPreview = truncateWords(popup?.description ?? "", 30);
  const isHomePage = pathname === "/";
  const shouldShowOnCurrentPage = Boolean(popup && (popup.show_on_all_pages || isHomePage));

  useEffect(() => {
    setOpen(false);
    if (!shouldShowOnCurrentPage || !popup) return;

    const baseKey = `store_popup_${popup.public_id}`;
    const today = formatLocalYmd(new Date());

    if (popup.show_frequency === "session") {
      if (sessionStorage.getItem(`${baseKey}_shown_session`)) return;
    } else if (popup.show_frequency === "daily") {
      if (localStorage.getItem(`${baseKey}_shown_daily_${today}`)) return;
    }

    const delayMs = Math.max(0, Number(popup.delay_seconds ?? 0)) * 1000;
    const timeoutId = window.setTimeout(() => {
      setOpen(true);
      if (popup.show_frequency === "session") {
        sessionStorage.setItem(`${baseKey}_shown_session`, "1");
      } else if (popup.show_frequency === "daily") {
        localStorage.setItem(`${baseKey}_shown_daily_${today}`, "1");
      }
    }, delayMs);

    return () => window.clearTimeout(timeoutId);
  }, [popup, shouldShowOnCurrentPage]);

  if (!shouldShowOnCurrentPage || !popup) return null;

  return (
    <DialogRoot open={open} onOpenChange={setOpen}>
      <DialogContent
        showCloseButton={false}
        className="rounded-none !px-0 !pt-0 sm:max-w-lg sm:rounded-none"
      >
        <div className="relative overflow-hidden border border-border bg-muted">
          <button
            type="button"
            onClick={() => setOpen(false)}
            aria-label="Close popup"
            className="absolute right-3 top-3 z-10 inline-flex size-8 items-center justify-center rounded-full bg-black/45 text-white backdrop-blur-sm transition-colors hover:bg-black/60"
          >
            <X className="size-4" strokeWidth={2.5} aria-hidden />
          </button>
          {heroImage ? (
            // eslint-disable-next-line @next/next/no-img-element
            <img
              src={heroImage}
              alt=""
              draggable={false}
              className="h-60 w-full object-cover sm:h-72"
            />
          ) : (
            <div className="h-60 w-full bg-muted sm:h-72" />
          )}
        </div>
        <div className="px-5 pb-4 pt-5">
          <DialogHeader className="text-center">
            <DialogTitle className="text-xl">{popup.title}</DialogTitle>
            <DialogDescription className="mt-1 text-sm text-muted-foreground">
              {descriptionPreview}
            </DialogDescription>
          </DialogHeader>

          <div className="mt-3 flex items-center justify-center gap-2">
            {buttonText && buttonLink ? (
              <a
                href={buttonLink}
                target="_blank"
                rel="noopener noreferrer"
                className="inline-flex h-10 cursor-pointer items-center justify-center rounded-md bg-primary px-4 text-sm font-semibold text-primary-foreground transition-colors hover:bg-primary/90"
              >
                {buttonText}
              </a>
            ) : null}
          </div>
        </div>
      </DialogContent>
    </DialogRoot>
  );
}

/**
 * Production API host baked into Paperbase tracker.js.
 * tracker.js calls are proxied through /api/tracker in development (no extra browser env).
 */
export const PAPERBASE_PRODUCTION_API_ORIGIN = "https://api.paperbase.me";

/**
 * Returns the local URL prefix that the fetch shim should use for tracker calls.
 * In development, points at the Next.js proxy route.
 */
export function getBrowserPaperbaseBackendOrigin(): string | null {
  if (process.env.NODE_ENV === "development") {
    return "/api/tracker";
  }
  return null;
}

/**
 * Rewrites hardcoded production API URLs for the fetch shim.
 * Maps ANY https://api.paperbase.me/* → /api/tracker/* in dev.
 */
export function rewritePaperbaseProductionFetchUrl(inputUrl: string, rewriteOrigin: string): string {
  if (!inputUrl.startsWith(PAPERBASE_PRODUCTION_API_ORIGIN)) {
    return inputUrl;
  }
  const remainder = inputUrl.slice(PAPERBASE_PRODUCTION_API_ORIGIN.length);
  return `/api/tracker${remainder}`;
}

import { categoryDisplayName } from "@/lib/category-display";
import {
  combinedSearch,
  getCatalogFilters,
  getCategoryBySlug,
  getProductDetail,
  getStorefrontHomeSections,
  listCategories,
  listProducts,
  searchProducts,
} from "@/lib/server/paperbase";
import type { Product, ProductDetail } from "@/types/product";
import type {
  PaperbaseProductDetail,
  PaperbaseProductListItem,
} from "@/types/paperbase";

function mapProduct(item: PaperbaseProductListItem): Product {
  return {
    public_id: item.public_id,
    name: item.name,
    slug: item.slug,
    image_url: item.image_url,
    price: item.price,
    original_price: item.original_price,
    stock_status: item.stock_status,
    available_quantity: item.available_quantity,
    variant_count: item.variant_count,
    brand: item.brand,
    category_public_id: item.category_public_id,
    category_slug: item.category_slug,
    category_name: item.category_name,
    extra_data: item.extra_data ?? {},
    prepayment_type: item.prepayment_type ?? "none",
  };
}

function mapProductDetail(item: PaperbaseProductDetail): ProductDetail {
  return {
    public_id: item.public_id,
    name: item.name,
    slug: item.slug,
    image_url: item.image_url,
    price: item.price,
    original_price: item.original_price,
    stock_status: item.stock_status,
    available_quantity: item.available_quantity,
    brand: item.brand,
    category_public_id: item.category_public_id,
    category_slug: item.category_slug,
    category_name: item.category_name,
    extra_data: item.extra_data ?? {},
    stock_tracking: item.stock_tracking,
    description: item.description,
    images: item.images ?? [],
    variants: item.variants ?? [],
    related_products: (item.related_products ?? []).map(mapProduct),
    prepayment_type: item.prepayment_type ?? "none",
  };
}

export async function getProductsForceCache(page = 1): Promise<Product[]> {
  const response = await listProducts({ page });
  return response.results.map(mapProduct);
}

export async function getProductsRevalidated(page = 1): Promise<Product[]> {
  const response = await listProducts({ page });
  return response.results.map(mapProduct);
}

export async function getProductsNoStore(page = 1): Promise<Product[]> {
  const response = await listProducts({ page });
  return response.results.map(mapProduct);
}

export async function getStorefrontProducts(page = 1): Promise<Product[]> {
  return getProductsRevalidated(page);
}

const HOME_CATEGORY_PRODUCT_LIMIT = 10;

export type StorefrontHomeCategorySection = {
  name: string;
  slug: string;
  description: string;
  products: Product[];
  showViewMore: boolean;
};

/** Root storefront categories with up to eight products each (for the home page). */
export async function getStorefrontHomeCategorySections(): Promise<StorefrontHomeCategorySection[]> {
  const payload = await getStorefrontHomeSections(HOME_CATEGORY_PRODUCT_LIMIT);
  return payload.sections
    .map((section) => ({
      name: categoryDisplayName(section.category.name),
      slug: section.category.slug,
      description:
        typeof section.category.description === "string" ? section.category.description.trim() : "",
      products: section.products.map(mapProduct),
      showViewMore: section.products.length >= HOME_CATEGORY_PRODUCT_LIMIT,
    }))
    .filter((section) => section.products.length > 0);
}

export async function getStorefrontProductDetail(identifier: string): Promise<ProductDetail | undefined> {
  try {
    const response = await getProductDetail(identifier);
    return mapProductDetail(response);
  } catch {
    return undefined;
  }
}

export async function getStorefrontProductSlugs(): Promise<string[]> {
  const firstPage = await listProducts({ page: 1 });
  return firstPage.results.map((product) => product.slug);
}

export async function getStorefrontSearchProducts(q: string, page = 1): Promise<Product[]> {
  const response = await searchProducts(q, page);
  return response.results.map(mapProduct);
}

/**
 * Full search UX: paginated products plus combined metadata (`GET /search/`).
 * Combined response supplies matching categories and name suggestions (capped by API).
 */
export async function getStorefrontSearchResults(q: string, _page = 1) {
  const query = q.trim();
  const combined = await combinedSearch({ q: query });
  return {
    count: combined.products.length,
    next: null,
    previous: null,
    products: combined.products.map(mapProduct),
    categories: combined.categories,
    suggestions: combined.suggestions,
  };
}

export async function getStorefrontCombinedSearch(q: string) {
  return combinedSearch({ q });
}

export async function getStorefrontCategoriesTree() {
  const response = await listCategories({ tree: "1" });
  return response;
}

export async function getStorefrontCategoryBySlug(slug: string) {
  return getCategoryBySlug(slug);
}

export async function getStorefrontCatalogFilters() {
  return getCatalogFilters();
}

"use client";

import { create } from "zustand";

import type { CartItem, CartMap } from "@/types/cart";

const CART_STORAGE_KEY = "storefront-cart";

/**
 * Where the user is acting: cart drawer / badge (`cart` → always `itemsMap`) vs checkout summary
 * (`checkout` → `buyNowMap` when a Buy Now session is active, else `itemsMap`).
 */
export type CartLineMutationScope = "cart" | "checkout";

type CartState = {
  /** Primary cart — keyed by `${product_public_id}::${variant_public_id ?? "default"}` */
  itemsMap: CartMap;
  hydrated: boolean;
  /**
   * Temporary checkout map for Buy Now flows.
   * Populated by `startBuyNow`, never persisted.
   * When non-null the checkout view reads from this map instead of `itemsMap`.
   */
  buyNowMap: CartMap | null;
  hydrateCart: () => void;
  addItem: (item: Omit<CartItem, "quantity">, quantity?: number) => void;
  removeItem: (
    productPublicId: string,
    variantPublicId?: string,
    scope?: CartLineMutationScope,
  ) => void;
  increment: (productPublicId: string, variantPublicId?: string, scope?: CartLineMutationScope) => void;
  decrement: (productPublicId: string, variantPublicId?: string, scope?: CartLineMutationScope) => void;
  clear: () => void;
  /**
   * Stateless Buy Now — clones `itemsMap`, merges the given item, and stores
   * the result in `buyNowMap` WITHOUT touching `itemsMap`.
   */
  startBuyNow: (item: Omit<CartItem, "quantity">, quantity?: number) => void;
  clearBuyNow: () => void;
  /**
   * Updates an existing line to a new variant (or refreshes fields) without changing
   * the logical line when the variant id is unchanged. When the variant id changes,
   * the line is moved to a new map key and quantity is clamped to the new max.
   */
  updateItemVariant: (
    productPublicId: string,
    oldVariantPublicId: string | undefined,
    updates: Omit<CartItem, "quantity">,
  ) => void;
  /**
   * Sets line quantity (or removes the line if quantity ≤ 0). Used when reconciling
   * cart lines with server stock. Optionally updates `max_quantity` from a fresh product fetch.
   */
  setLineQuantity: (
    productPublicId: string,
    variantPublicId: string | undefined,
    quantity: number,
    scope?: CartLineMutationScope,
    patch?: { max_quantity?: number; unsetMaxQuantity?: boolean },
  ) => void;
};

export function getItemKey(productPublicId: string, variantPublicId?: string) {
  return `${productPublicId}::${variantPublicId ?? "default"}`;
}

function persistMap(map: CartMap) {
  if (typeof window === "undefined") return;
  window.localStorage.setItem(CART_STORAGE_KEY, JSON.stringify(map));
}

function clampToMax(quantity: number, maxQuantity?: number) {
  if (maxQuantity == null || !Number.isFinite(maxQuantity)) return quantity;
  return Math.min(quantity, Math.max(0, maxQuantity));
}

function newLineKey(): string {
  try {
    return globalThis.crypto.randomUUID();
  } catch {
    return `lk_${Date.now()}_${Math.random().toString(36).slice(2, 11)}`;
  }
}

function assignMissingLineKeys(map: CartMap): { map: CartMap; changed: boolean } {
  let changed = false;
  const next: CartMap = { ...map };
  for (const key of Object.keys(next)) {
    const item = next[key];
    if (!item) continue;
    if (!item.line_key) {
      next[key] = { ...item, line_key: newLineKey() };
      changed = true;
    }
  }
  return { map: next, changed };
}

/**
 * Reads localStorage and normalises the value to a `CartMap`.
 * Handles backward-compat migration from the previous `CartItem[]` format.
 */
function loadMapFromStorage(): CartMap {
  if (typeof window === "undefined") return {};
  const raw = window.localStorage.getItem(CART_STORAGE_KEY);
  if (!raw) return {};
  try {
    const parsed: unknown = JSON.parse(raw);
    // Migration: old format was an array
    if (Array.isArray(parsed)) {
      const migrated: CartMap = {};
      for (const item of parsed as CartItem[]) {
        const key = getItemKey(item.product_public_id, item.variant_public_id);
        migrated[key] = item;
      }
      persistMap(migrated);
      return migrated;
    }
    return parsed as CartMap;
  } catch {
    return {};
  }
}

/**
 * Core merge: inserts or quantity-merges `item` into a map clone.
 * Always returns a new object — never mutates the input map.
 */
function mergeItemIntoMap(
  map: CartMap,
  item: Omit<CartItem, "quantity">,
  quantity: number,
): CartMap {
  const safeQty = Math.max(1, quantity);
  const key = getItemKey(item.product_public_id, item.variant_public_id);
  const existing = map[key];

  if (existing) {
    const maxQ = item.max_quantity ?? existing.max_quantity;
    return {
      ...map,
      [key]: {
        ...existing,
        line_key: existing.line_key ?? item.line_key ?? newLineKey(),
        quantity: clampToMax(existing.quantity + safeQty, maxQ),
        max_quantity: maxQ ?? existing.max_quantity,
        product_slug: item.product_slug ?? existing.product_slug,
        price: item.price,
        name: item.name,
        image_url: item.image_url ?? existing.image_url,
        variant_public_id: item.variant_public_id ?? existing.variant_public_id,
        variant_details: item.variant_details ?? existing.variant_details,
        prepayment_type: item.prepayment_type ?? existing.prepayment_type,
      },
    };
  }

  const maxQ = item.max_quantity;
  return {
    ...map,
    [key]: {
      ...item,
      line_key: item.line_key ?? newLineKey(),
      quantity: clampToMax(safeQty, maxQ),
      max_quantity: maxQ,
    },
  };
}

/** Snapshot of cart lines used for checkout (Buy Now map when active, else main cart). */
export function getCheckoutCartItems(): CartItem[] {
  const state = useCartStore.getState();
  const map = state.buyNowMap ?? state.itemsMap;
  return Object.values(map);
}

/** Resolves which map to read/write for increment/decrement/remove. */
function getLineMutationTarget(
  state: CartState,
  scope: CartLineMutationScope,
): { map: CartMap; persist: boolean } {
  if (scope === "checkout" && state.buyNowMap != null) {
    return { map: state.buyNowMap, persist: false };
  }
  return { map: state.itemsMap, persist: true };
}

export const useCartStore = create<CartState>((set, get) => ({
  itemsMap: {},
  hydrated: false,
  buyNowMap: null,

  hydrateCart: () => {
    const loaded = loadMapFromStorage();
    const { map, changed } = assignMissingLineKeys(loaded);
    if (changed) persistMap(map);
    set({ itemsMap: map, hydrated: true });
  },

  addItem: (item, quantity = 1) => {
    const nextMap = mergeItemIntoMap(get().itemsMap, item, quantity);
    persistMap(nextMap);
    set({ itemsMap: nextMap, buyNowMap: null });
  },

  removeItem: (productPublicId, variantPublicId, scope = "cart") => {
    const state = get();
    const key = getItemKey(productPublicId, variantPublicId);
    const { map: sourceMap, persist } = getLineMutationTarget(state, scope);
    const nextMap = { ...sourceMap };
    delete nextMap[key];
    if (persist) {
      persistMap(nextMap);
      set({ itemsMap: nextMap });
    } else {
      set({ buyNowMap: nextMap });
    }
  },

  increment: (productPublicId, variantPublicId, scope = "cart") => {
    const state = get();
    const key = getItemKey(productPublicId, variantPublicId);
    const { map: sourceMap, persist } = getLineMutationTarget(state, scope);
    const existing = sourceMap[key];
    if (!existing) return;
    const cap = existing.max_quantity ?? Number.MAX_SAFE_INTEGER;
    if (existing.quantity >= cap) return;
    const nextMap = {
      ...sourceMap,
      [key]: { ...existing, quantity: existing.quantity + 1 },
    };
    if (persist) {
      persistMap(nextMap);
      set({ itemsMap: nextMap });
    } else {
      set({ buyNowMap: nextMap });
    }
  },

  decrement: (productPublicId, variantPublicId, scope = "cart") => {
    const state = get();
    const key = getItemKey(productPublicId, variantPublicId);
    const { map: sourceMap, persist } = getLineMutationTarget(state, scope);
    const existing = sourceMap[key];
    if (!existing || existing.quantity <= 1) return;
    const nextMap = {
      ...sourceMap,
      [key]: { ...existing, quantity: existing.quantity - 1 },
    };
    if (persist) {
      persistMap(nextMap);
      set({ itemsMap: nextMap });
    } else {
      set({ buyNowMap: nextMap });
    }
  },

  clear: () => {
    persistMap({});
    set({ itemsMap: {}, buyNowMap: null });
  },

  startBuyNow: (item, quantity = 1) => {
    const merged = mergeItemIntoMap(get().itemsMap, item, quantity);
    const { map } = assignMissingLineKeys(merged);
    set({ buyNowMap: map });
  },

  clearBuyNow: () => set({ buyNowMap: null }),

  updateItemVariant: (productPublicId, oldVariantPublicId, updates) => {
    const state = get();
    const isBuyNow = state.buyNowMap != null;
    const sourceMap = isBuyNow ? state.buyNowMap! : state.itemsMap;
    const oldKey = getItemKey(productPublicId, oldVariantPublicId);
    const existing = sourceMap[oldKey];
    if (!existing) return;

    const newKey = getItemKey(productPublicId, updates.variant_public_id);
    const merged: CartItem = {
      ...existing,
      ...updates,
      quantity: existing.quantity,
    };
    const clampedQty = clampToMax(merged.quantity, merged.max_quantity);
    const nextItem: CartItem = { ...merged, quantity: clampedQty };

    let nextMap: CartMap;
    if (newKey === oldKey) {
      nextMap = { ...sourceMap, [oldKey]: nextItem };
    } else {
      const rest = { ...sourceMap };
      delete rest[oldKey];
      const { quantity: qty, ...payload } = nextItem;
      nextMap = mergeItemIntoMap(rest, payload, qty);
    }

    if (isBuyNow) {
      set({ buyNowMap: nextMap });
    } else {
      persistMap(nextMap);
      set({ itemsMap: nextMap });
    }
  },

  setLineQuantity: (productPublicId, variantPublicId, quantity, scope = "cart", patch) => {
    if (quantity <= 0) {
      get().removeItem(productPublicId, variantPublicId, scope);
      return;
    }
    const state = get();
    const key = getItemKey(productPublicId, variantPublicId);
    const { map: sourceMap, persist } = getLineMutationTarget(state, scope);
    const existing = sourceMap[key];
    if (!existing) return;

    const cap =
      patch?.max_quantity ?? existing.max_quantity ?? Number.MAX_SAFE_INTEGER;
    const q = clampToMax(quantity, cap);
    if (q <= 0) {
      get().removeItem(productPublicId, variantPublicId, scope);
      return;
    }

    let nextItem: CartItem = { ...existing, quantity: q };
    if (patch?.unsetMaxQuantity) {
      const { max_quantity: _drop, ...rest } = nextItem;
      nextItem = { ...rest, quantity: q };
    } else if (patch?.max_quantity !== undefined) {
      nextItem = { ...nextItem, max_quantity: patch.max_quantity };
    }

    const nextMap = { ...sourceMap, [key]: nextItem };
    if (persist) {
      persistMap(nextMap);
      set({ itemsMap: nextMap });
    } else {
      set({ buyNowMap: nextMap });
    }
  },
}));
